sql:
SELECT DISTINCT patient_id
FROM appointments
WHERE status IN ('Pending', 'Accepted');

SELECT patient_id
FROM patients
WHERE patient_id IN (
    SELECT patient_id
    FROM referrals
)
AND patient_id NOT IN (
    SELECT patient_id
    FROM appointments
);

SELECT COUNT(patient_id) AS total_referrals
FROM referrals
WHERE reason = 'Diabetes';

SELECT p.name, a.appointment_date, a.appointment_type, a.location
FROM patients p
INNER JOIN appointments a ON p.patient_id = a.patient_id;

SELECT follow_up_type
FROM follow_ups
WHERE patient_id = 1;

SELECT patients.name, lab_tests.results
FROM patients
INNER JOIN lab_tests ON patients.patient_id = lab_tests.patient_id;

SELECT reason, status
FROM appointments
WHERE patient_id = 0;

SELECT p.name
FROM patients p
WHERE strftime('%Y', 'now') - strftime('%Y', p.date_of_birth) > 60;
